SELECT COUNT(electrician_id) AS female_electrician_count
FROM electricians
WHERE gender = 'Female';

SELECT application_date
FROM license_renewals
WHERE status = 'Pending';

SELECT report_date, description, status
FROM public_reports
WHERE report_date BETWEEN '2023-10-01' AND '2023-12-31';

SELECT gender, COUNT(*) as gender_count
FROM electricians
GROUP BY gender;

SELECT first_name, last_name
FROM electricians
ORDER BY date_of_birth ASC;

SELECT COUNT(DISTINCT electrician_id) AS non_compliant_count
FROM compliance
WHERE status = 'Non-compliant';

SELECT description, category
FROM business_rules
WHERE mandatory = 1;

SELECT COUNT(*) AS pending_renewals
FROM license_renewals
WHERE status = 'Pending';
